VALUES
  ('heelevel3-6f0ba476-moex-00072', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '根據貨物稅條例，下列敘述何者錯誤？', '["產製貨物者，貨物稅納稅義務人為產製廠商", "產製貨物者，貨物稅課徵時點，為出廠時", "產製廠商當月份出廠貨物之應納稅款，應於次月 15 日以前自行向公庫繳納，並依照財政部規 定之格式填具計算稅額申報書，檢同繳款書收據向主管稽徵機關申報；無應納稅額者，仍應向 主管稽徵機關申報", "產製廠商逾法定期限未申報者，主管稽徵機關應即通知於15日內繳稅補辦申報"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00073', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依土地稅法之規定，下列敘述何者錯誤？', '["地價稅以每年8月31日為納稅義務基準日", "土地增值稅納稅義務人於收到土地增值稅繳納通知書後，應於90日內向公庫繳納", "欠繳土地稅之土地，在欠稅未繳清前，不得辦理移轉登記或設定典權", "農業用地閒置不用，經直轄市或縣（市）政府報經內政部核准通知限期使用或命其委託經營， 逾期仍未使用或委託經營者，按應納田賦加徵一倍至三倍之荒地稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00074', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依目前法律，下列何者並非「免徵房屋稅之私有房屋」？', '["農會所有之自用倉庫，經主管機關證明", "專供飼養禽畜之房舍", "業經立案之私立學校，完成財團法人登記者，其供校舍或辦公使用之自有房屋", "經目的事業主管機關許可設立之公益信託，其受託人因該信託關係而取得之房屋，直接供辦理 公益活動使用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00075', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依土地稅法規定，下列敘述何者錯誤？', '["已規定地價之土地，於土地所有權移轉時，除法律另有規定外，應按其土地漲價總數額徵收土 地增值稅", "配偶相互贈與之土地，得申請不課徵土地增值稅，於再移轉依法應課徵土地增值稅時，以配偶 相互贈與時之規定地價為原地價，計算漲價總數額，課徵土地增值稅", "因繼承而移轉之土地，免徵土地增值稅", "土地為信託財產者，於信託關係存續中受託人變更時，所有權自原受託人移轉至新受託人，不 課徵土地增值稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00076', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '關於產業創新條例之租稅優惠規定，下列敘述何者錯誤？', '["公司員工取得獎酬員工股份基礎給付，於取得股票當年度或可處分日年度按時價計算全年合計 新臺幣五百萬元總額內之股票，得選擇免予計入當年度應課稅所得額課稅，一經擇定不得變更", "公司員工取得獎酬員工股份基礎給付，依法選擇免予計入取得股票或可處分日當年度課稅，自 取得股票日起，持有股票且繼續於該公司服務累計達2年者，於實際轉讓或帳簿劃撥至開設之 有價證券保管劃撥帳戶時，其全部轉讓價格、贈與或作為遺產分配時之時價或撥轉日之時價， 高於取得股票或可處分日之時價者，以取得股票或可處分日之時價，作為該轉讓或撥轉年度之 收益，依所得稅法規定計算所得並申報課徵所得稅", "所謂「員工繼續於該公司服務累計達 2 年之期間」，倘發行獎酬員工股份基礎給付公司持有他 公司有表決權之股份或出資額，超過該他公司已發行有表決權之股份總數或資本總額百分之五 十，員工繼續於該他公司服務之期間，得合併計算", "「公司員工取得獎酬員工股份基礎給付」所稱「公司員工」，包括發行獎酬員工股份基礎給付公 司之董事及監察人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
