  ('heelevel3-6f0ba476-moex-00081', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '有關遺產稅之規定，下列何者錯誤？', '["被繼承人自己創作之著作權、發明專利權及藝術品，不併入遺產總額計稅", "被繼承人死亡前5年內繼承之財產，不併入遺產總額計稅", "被繼承人死亡前，依法應納之各項境內稅捐、罰鍰及罰金，應自遺產總額中扣除，免徵遺產稅", "被繼承人死亡前2年內贈與配偶之財產，應於被繼承人死亡時，視為被繼承人之遺產，併入其 遺產總額計稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
